#include<bits/stdc++.h>
using namespace std;
long long a[100010],b[100010],rnk[100010],d[100010],siz[100010],fa[100010],top[100010],dfncnt,dfn[100010],son[100010],val[100010];
vector<long long> mp[100010];
void dfs1(long long x,long long f=-1)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    top[x]=t;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(long long i:mp[x])
        {
            if(i!=son[x]&&i!=fa[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long max1,min1,ansl,ansr;
        long long tag;
    }t[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        long long ls=t[x].lson,rs=t[x].rson;
        t[x].max1=max(t[ls].max1,t[rs].max1);
        t[x].min1=min(t[ls].min1,t[rs].min1);
        t[x].ansl=max({t[ls].ansl,t[rs].ansl,t[rs].max1-t[ls].min1});
        t[x].ansr=max({t[ls].ansr,t[rs].ansr,t[ls].max1-t[rs].min1});
    }
    void pushup(node &x,node ls1,node rs1)
    {
        node ls=ls1,rs=rs1;
        x.max1=max(ls.max1,rs.max1);
        x.min1=min(ls.min1,rs.min1);
        x.ansl=max({ls.ansl,rs.ansl,rs.max1-ls.min1});
        x.ansr=max({ls.ansr,rs.ansr,ls.max1-rs.min1});
    }
    void pushadd(int x,int v)
    {
        t[x].max1+=v;
        t[x].min1+=v;
        t[x].tag+=v;
    }
    void pushdown(int x)
    {
        int ls=t[x].lson,rs=t[x].rson;
        long long tg=t[x].tag;
        pushadd(ls,tg);
        pushadd(rs,tg);
        t[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        t[x].tag=0;
        if(l==r)
        {
            t[x].max1=t[x].min1=val[rnk[l]];
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long v)
    {
        if(t[x].l>r||t[x].r<l)
        {
            return;
        }
        if(l<=t[x].l&&t[x].r<=r)
        {
            pushadd(x,v);
            return;
        }
        pushdown(x);
        add(t[x].lson,l,r,v);
        add(t[x].rson,l,r,v);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        long long mid=(t[x].l+t[x].r)>>1;
        pushdown(x);
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
constexpr int p=1e9;
long long getans(long long x,long long y)
{
    segment_tree::node ansl=(segment_tree::node){0,0,0,0,-p,p,0,0,0};
    auto ansr=ansl;
    while(top[x]!=top[y])
    {
        segment_tree::node now;
        if(d[top[x]]<d[top[y]])
        {
            now=t.query(1,dfn[top[y]],dfn[y]);
            t.pushup(ansr,now,ansr);
            y=fa[top[y]];
        }
        else
        {
            now=t.query(1,dfn[top[x]],dfn[x]);
            t.pushup(ansl,now,ansl);
            x=fa[top[x]];
        }
    }
    segment_tree::node now;
    if(d[x]<d[y])
    {
        now=t.query(1,dfn[x],dfn[y]);
        t.pushup(ansr,now,ansr);
    }
    else
    {
        now=t.query(1,dfn[y],dfn[x]);
        t.pushup(ansl,now,ansl);
    }
    return max({ansl.ansr,ansr.ansl,ansr.max1-ansl.min1});
}
void add(long long x,long long y,long long v)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        t.add(1,dfn[top[x]],dfn[x],v);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    t.add(1,dfn[x],dfn[y],v);
}
int main()
{
    long long n,q;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&val[i]);
    }
    for(long long i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,n);
    scanf("%lld",&q);
    while(q--)
    {
        long long a,b,v;
        scanf("%lld%lld%lld",&a,&b,&v);
        printf("%lld\n",getans(a,b));
        add(a,b,v);
    }
    return 0;
}
